    TQue<TPosition::VECIN, BUFFER_NUM> inQueueH_;
    TQue<TPosition::VECIN, 1> inQueueWI2H_;
    TQue<TPosition::VECIN, 1> inQueueBI2H_;
    TQue<TPosition::VECIN, 1> inQueueWH2O_;
